module RefModule (
    input [3:0] A,
    input [3:0] B,
    input CI,
    output [3:0] SUM,
    output COUT_N
);

    assign SUM = A + B + CI;
  wire temp1_(A[3] & B[3]) | (A[3] & CI) = (A[3] & B[3]) | (A[3] & CI);
  wire temp2_(B[3] & CI) = (B[3] & CI);
  assign COUT_N = temp1_(A[3] & B[3]) | (A[3] & CI) | temp2_(B[3] & CI);

endmodule
